window.__QUIZ_SUBJECT__=[{"id": "theory>Data Processing>2016>1>a>i", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Describe data handling", "images": [], "marking_scheme": "Data handling is the process of ensuring that research data is stored, archived or disposed off in a safe and secure manner during and after the conclusion of a research project. This includes the development of policies and procedures to manage data handled electronically as well as through non-electronic means .    Data handling is important in ensuring the integrity of research data since it addresses concerns related to confidentially, security, and preservation/retention of research data. Proper planning for data handling can also result in efficient and economical storage, retrieval, and disposal of data. In the case of data handled electronically, data integrity is a primary concern to ensure that recorded data is not altered, erased, lost or accessed by unauthorized users.", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2016>1>a>ii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Explain two ways of handling data", "images": [], "marking_scheme": "There are two ways of handling   - Electronic Method- This is the use of Electronic systems such as computer workstations and laptops, personal digital assistants (PDA), storage media such as videotape, diskette, CD, DVD, memory cards, and other electronic instrumentation. These systems may be used for storage, archival, sharing, and disposing off data, and therefore, require adequate planning at the start of a research project so that issues related to data integrity can be analyzed and addressed early on.   - Non Electronic Method- This involves the use of Paper files, Journals, laboratory notebook, human effect and all other non-electronic means to share or store data.", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2016>1>a>iii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "iii", "group": "", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "State four factors to consider when handling data electronically", "images": [], "marking_scheme": "- Data integrity  - Regular update of data  - Validation of data  - Security of data/encryption  - Type of data   - Type of storage to be used  - Data volume/size  - Access control  - Regular anti-virus update  - Limit physical access to storage media  - Regular backups  - Ensure data recoverability  - Login/password  - Record date and time  - Power supply", "marks": "5", "difficulty": "3"}, {"id": "theory>Data Processing>2016>1>b", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Starting from the Save As Dialogue box, outline steps involved in passwording a document in a word processing package", "images": [], "marking_scheme": "- Go to File -> Info  - Click on the \"Protect Document\" drop down button  - Encrypt with Password  - A new dialog window will open asking to enter the encryption password. Enter the password and press OK.  - You will need to re-enter the password and press OK again.", "marks": "5", "difficulty": "3"}, {"id": "theory>Data Processing>2016>2>a", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Define information processing", "images": [], "marking_scheme": "It is the process of acquiring/obtaining/collecting/gathering/retrieving, manipuating/handling/analysing, presenting/display/dissemination of information.", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2016>2>b", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "State four steps involved in information processing", "images": [], "marking_scheme": "- collation of information  - organization of information  - analysis of information  - interpretation of information", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2016>2>c", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Mention three advantages of using computers for information processing", "images": [], "marking_scheme": "- Efficiency  - Automation  - Reliability  - Volume/storage  - High speed  - Accuracy  - Security  - Sharing of information  - Economical  - Lower overall cost  - Versatility  - Service improvement  - Easy retrieval", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2016>2>d", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Highlight three disadvantages of using computers for information processing.", "images": [], "marking_scheme": "- High initial investment cost  - Loss of job due to computerization  - Required specialized personnel  - Extra cost of retraining staff  - Virus/hackers susceptibility  - Face to face interaction among staff maybe reduced  - Prone unauthorized access  - Power dependent  - Overwriting/loss of data  - System failure/system malfuctioning", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2016>3>a>i", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "i", "group": "", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "With the aid of simple diagram, explain information processing", "images": ["Data Processing/imgs/2016/information.png"], "marking_scheme": "Information processing the processing of information, typically by a computer or by an organism, so as to yield new or more useful information..    NB- Information transmission is the act of transferring something from one spot to another, like a radio or TV broadcast, or a disease going from one person to another.", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2016>3>a>ii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Give one example of information transmission", "images": [], "marking_scheme": "- Printing of documents, class room instruction, radio signals, DSTV signals, Telegraph, GSM, photography, facsimile, town crying etc", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2016>3>b>i", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Give one example each of the following:    Single user, Single tasking operating system;", "images": [], "marking_scheme": "- DOS, OS 2, PC-DOS, Palm-OS", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2016>3>b>ii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Give one example each of the following:Single user, muti tasking operating system;", "images": [], "marking_scheme": "- Ms Windows, Mac OS, Linux", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2016>3>b>iii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Give one example each of the following:muti user operating system", "images": [], "marking_scheme": "Xenix, Zenix, Unix, Linus, Mac OS, VMS, Mainframe OS", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2016>3>c", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "List four features of a Graphical User Interface", "images": [], "marking_scheme": "- Windows   - Icons  - Menus  - Pointing device(mouse)", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2016>4>a", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "Mention four qualities of a good computer professional", "images": [], "marking_scheme": "- Multi tasking ability  - Adaptability   - Analytical skills  - Attention to detail/Accuracy  - Committed to learning/ abreast with new trends   - Communication skills  - Problem solving/ troubleshooting capabilities  - Competence  - Technical writing skills  - Aptitude for mathematics   - Ability to memorise   - Certification   - Reliability  - Disciplined  - Trustworthy", "marks": "7", "difficulty": "1"}, {"id": "theory>Data Processing>2016>4>b", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "List four computer professional bodies in Nigeria", "images": [], "marking_scheme": "- Computer Professionals Registration Council of Nigeria  - Nigeria Computer Society(NCS)  - The Institute of Software Practitioners of Nigeria(ISPON)  - Information Technology Industry Association of Nigeria(ITAN)  - Nigeria Internet Group(NIG)  - Internet Service Providers Association of Nigeria(ISPAN)", "marks": "7", "difficulty": "1"}, {"id": "theory>Data Processing>2016>4>c>i", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Write the full meaning of the following:    - WIFI", "images": [], "marking_scheme": "- Wireless Fidelity", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2016>4>c>ii", "subject": "Data Processing", "year": "2016", "type": "Theory", "sub_label": "ii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Write the full meaning of the following:GUI", "images": [], "marking_scheme": "- Graphical User Interface", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2017>1>a", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "State four classes of computer base on size", "images": [], "marking_scheme": "- Super computer  - Mainframe computer  - Mini computer  - Micro computer", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2017>1>b", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Define the term Information and Communication Technology (ICT)", "images": [], "marking_scheme": "Information and Communication Technology (ICT) is a diverse means of collecting, processing, storing and transmitting information using modern equipments gadgets devices.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2017>1>c", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Highlight three ways ICT has impacted on the society", "images": [], "marking_scheme": "- Enhance communication speed  - Lower communication cost  - Reliable mode of communication  - Effective sharing of information  - Paperless environment  - Health problems   - Social problems(cyber crime, hacker's threat)  - Improved quality of instruction   - Entertainment and sports  - Security and control  - Military  - Physical and mental stress  - Uemployment   - Improved service delivery", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2017>2>a", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "What is computer Ethics?", "images": [], "marking_scheme": "Computer Ethics. Ethics is a set of moral principles that govern the behavior of a group or individual. Some common issues of computer ethics include intellectual property rights (such as copyrighted electronic content), privacy concerns, and how computers affect society.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2017>2>b", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "b", "group": "", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "State three computer room managent ethics", "images": [], "marking_scheme": "- Maintaining dust free enviroment  - Appropriate ventilation  - Appropriate lightning  - Setting computers before student comes in  - Avoidance of liquid  - Avoidance of explosion  - Switching off apparatus after use   - Proper sitting arrangement  - Avoid unauthorized access  - Avoid use of device from untrusted source", "marks": "1", "difficulty": "2"}, {"id": "theory>Data Processing>2017>2>c", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "List five laboratory rules and regulations", "images": [], "marking_scheme": "- Lab users must sign in and out of the lab.  - NO FOOD, DRINK, OR USE OF TOBACCO IN ANY FORM is allowed in the labs.  - Telephones are NOT for personal use.  - TURN OFF CELL PHONES! If you need to use it, please take it to the hallway.  - The only game allowed is Solitaire.  - Children under the age of 16 must be accompanied and supervised by an adult. If supervision does not occur, or the situation becomes disruptive, the adult and child(ren) will be asked to leave.  - Lab users should maintain professional and courteous communication. Electronic devices should be used on a professional level. No obnoxious or belligerent behavior will be tolerated.  - Please operate the equipment with respect and care.  - Activities in the lab(s) that are considered by the lab aides to be abusive to the software, hardware, and\\or personnel may result in expulsion from the lab(s) and denial of future use of the lab(s).  - Excessive use of paper and materials may require reimbursement to the lab. Paper being discarded should be placed in a recycle container.  - The lab aides are here to help when they can and to maintain the labs' operation. However, the lab aides are not here to do your work for you. The lab aides will refer students to their instructors at the lab aides discretion.  - Software may be installed by Computer Labs staff only. Do not install any software on your own. Files not put on by Computer Labs staff will be routinely removed.  - Do not modify any software or files. Do not overwrite the operating system, modify the autoexec.bat or config.sys or any other system parameters.  - For any hardware, software, printer, paper, or ink problems, please contact a aide.  - College policy requires compliance with all U.S. copyright laws. Copying software without appropriate authorization violates these laws. Illegal use of materials in the labs is grounds for denial of use of the labs and confiscation of illegally used materials.  - Any failure to follow these lab rules may result in the loss of your lab privileges.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2017>3>a", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Mr Okafor has a company that specializes in the production of beverages with headquarters in Abuja. He intends to monitor the sales and transactions in the company branches accross Nigeria as well as interact with his customers.", "images": [], "marking_scheme": "- Through the company's website", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2017>3>b", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "b", "group": "", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "Which computer professional should Mr Okafor hire to design to design the platform in 3(a).", "images": [], "marking_scheme": "- Web/Website developer(programmer)", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>3>c", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "c", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "State two software needed to create the platform for Mr Okafor.", "images": [], "marking_scheme": "Website designs packages  - Adobe dream weaver  - Adobe Muse  - Amaya  - Antena web  - Blue fish  - Blue Griffon  - Design studio  - Galaxy web  - Go daddy  - Google web design  - Rapid weaver  - H5P  - HTML  - Iweb  - Microsoft frontpage  - MySQI  - Net object fusion", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>3>d>i", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "If Mr Okafor decides to connect all offices within the headquarters in Abuja in a single network    What type of Network is appropriate?", "images": [], "marking_scheme": "- Local Area Network/LAN Intranet", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>3>d>ii", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "If Mr Okafor decides to connect all offices within the headquarters in Abuja in a single networkMention three reasons to support his decision", "images": [], "marking_scheme": "- File sharng  - Printer sharing  - Sharing of media  - Media centre server  - Security  - Communiction  - Sharing of resources   - Reduced cost  - Improved customer service  - Better perfomance  - Easy of setup", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>3>e", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "e", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Mention two transmission media that can be used to implement the network in 3d(i)", "images": [], "marking_scheme": "- UTP  - STP  - Coaxial/Copper  - Fibre optics  - Bluetooth  - Infared  - Radio  - WIFI  - Hot spot  - Satelites", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2017>4>a", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Define the term Software Maintenance", "images": [], "marking_scheme": "- Software maintenance in software engineering is the modification of a software product after delivery to correct faults, to improve performance or other attributes. A common perception of maintenance is that it merely involves fixing defects", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2017>4>b", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "List four types of software maintenance", "images": [], "marking_scheme": "The basic types of maintenance falling under MRO include:  - Preventive or scheduled maintenance, where equipment or facilities are inspected, maintained and protected before break down or other problems occur.  - Corrective maintenance where equipment is repaired or replaced after wear, malfunction or break down.  - Predictive maintenance, which uses sensor data to monitor a system, then continuously evaluates it against historical trends to predict failure before it occurs.  - Adaptive maintenance", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2017>4>c", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "State four importance of software maintenance", "images": [], "marking_scheme": "- To correct faults(scanning and virus remover)  - To remove performance(software upgrade)  - To adapt to a changing environment    - To prevent frauds(Installation on Anti Virus)  - To profer solution to identified software problems   - To predict software expenses(predictive cash flow)", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2017>5>a>i", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A teacher asked a student to capture and  print out one-slide presentation assignment using MS Word, showing everything on the screen.    What keys or combination of keys can be used to carry out this operation?", "images": [], "marking_scheme": "- Print Screen (PrtSc) OR Ctrl + PrtSc Or Alt Prtsc  - Ctrl + V  - Ctrl + P", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>5>a>ii", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A teacher asked a student to capture and  print out one-slide presentation assignment using MS Word, showing everything on the screen. Describe the procedure to be followed by the students in carrying this assignment using the keyboard.", "images": [], "marking_scheme": "- In Microsoft Powerpoint, Press \"PrtSc\" or Ctrl + PrtSc  - Launch Microsoft word/Open blank document  - Press Ctrl + V / Paste  - Press Ctrl P", "marks": "1", "difficulty": "3"}, {"id": "theory>Data Processing>2017>5>b>i", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A system analyst was hired to set up a computer laboratory for Bofe International School    Mention three hardware devices the analyst would need to set up the laboratory", "images": [], "marking_scheme": "- Monitor  - Keyboard  - Mouse  - Speaker  - Printer  - Scanner  - Inverter  - Photcopier  - UPS  - System unit  - Network devices  - Routers  - Hubs  - Back up devices  - Power stabilizers  - Modem  - Surge protector  - Switches", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>5>b>ii", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A system analyst was hired to set up a computer laboratory for Bofe International SchoolList three database application packages likely to be recommended by the analyst", "images": [], "marking_scheme": "- ADABAS  - IBM DB2  - Microsoft Access  - Microsoft Excel  - Microsoft SQL Server  - MySQL  - Oracle RDBMS  - QuickBase  - SAP Sybase ASE  - Teradata", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>5>b>iii", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A system analyst was hired to set up a computer laboratory for Bofe International SchoolState three Word processing packages likely to be installed", "images": [], "marking_scheme": "- AbiWord  - Apache OpenOffice Writer  - Calligra Words  - EtherPad – real-time word processor  - GNU TeXmacs  - Groff  - JWPce – Japanese word processor, designed primarily for the English speaker who is reading or writing in Japanese  - KWord  - LibreOffice Writer  -  LyX  - OnlyOffice Desktop Editors  - Ted  - Apple Pages, part of its iWork suite – Mac  - Applix Word – Linux  - Documents To Go – Android, iOS, Windows Mobile, Symbian  - Final Draft – screenplay/teleplay word processor  - FrameMaker  - Gobe Productive Word Processor  - Han/Gul (a.k.a. HWP)  - IA Writer – Mac, iOS  - IBM SCRIPT – IBM VM/370  - IBM SCRIPT/VS – IBM z/VM or z/OS systems  - Ichitaro – Japanese word processor produced by JustSystems  - InCopy  - IntelliTalk  - iStudio Publisher – Mac  - Kingsoft Writer – Windows and Linux  - Mariner Write – Mac  - Mathematica – technical and scientific word processing  - Mellel – Mac  - Microsoft Word – Windows and Mac  - Microsoft Works Word Processor  - Microsoft Write – Windows and Mac (a stripped-down version of Word)  - Nisus Writer – Mac  - Nota Bene – Windows  - Polaris Office – Android and Windows Mobile  - PolyEdit  - QuickOffice – Android, iOS, Symbian  - Scrivener  - TechWriter – RISC OS  - TextMaker  - ThinkFree Office Write  - WordPad – previously known as \"Write\" in older versions than Windows 95; has been included in all versions of Windows since Windows 1.01. Source code available from Microsoft as an example.  - WordPerfect", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2017>5>c", "subject": "Data Processing", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Complete Table 1 on keyboard shortcuts  SNKeystrokeActioni  Page breakii Ctrl+Fiii F1 iv Ctrl+F2", "images": [], "marking_scheme": "SNKeystrokeActioni Ctrl + Enter/Return Page breakii Ctrl+FFindiii F1Help iv Ctrl+F2Print Preview", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2019>1>a", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "What is teleconferencing?", "images": [], "marking_scheme": "A teleconferencing is the live exchange and mass articulation of information among several persons and machines remote from one another but linked by a telecommunication system.  OR  A tele conferencing is a telephone meeting among two or more participants involving technology more sophisticated than a simple two-way phone connection.  OR  Teleconferencing means meeting through a telecommunication medium.", "marks": "6", "difficulty": "1"}, {"id": "theory>Data Processing>2019>1>b", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "State four uses of Automated Teller Machine (ATM).", "images": [], "marking_scheme": "- Shopping  - Recharging airtime on mobile phones and devices  - Cash withdrawer  - Intra bank transfer  - Inter bank transfer  - Check account balance  - Check account number", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2019>1>c>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Give the function of a modem.", "images": [], "marking_scheme": "- To transmit digital information via analog system.  - To modulate an analog carrier signal to carry digital information.  - To demodulate a similar signal so as to decode the digital information from the analog carrier signal.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2019>1>c>ii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "List the two means of transmitting information.", "images": [], "marking_scheme": "i. Ancient method; this include:  - oral  - beaten drums  - town crier  - whistling  - drawing diagrams  - making representation    ii. Modern method: This include:  - print out copies   - telephone  - radio  - television  - internet  - satellite", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2019>2", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Hamza, Emeka, Funsho, Fejiro and Idongesit were friends from secondary school. Now, Hamza is a pilot. Emeka is a businessman. Funsho is a banker, Fejiro is a manufacturer while Idongesit is a teacher.  State two ways by which each of these friends can apply ICT in their respective professions.", "images": [], "marking_scheme": "(i) As a Pilot: As a pilot, one can use ICT in the following areas:  - For storing of all operations and communications on the flight into a data recorder and a flight recorder or black box so as to guide investigation if an accident occurs.    - With the use of ICT, flying has made quite a safe mode of travel.    - ICT use in aviation extends to booking, scheduling, flight control, payments, radar operation, weight determination, balance of air craft, loading, communication to ground based station, instrument readings and display warning signals, fire detection, engine performance monitoring, emergency operation, cargo tagging and tracking etc.    (ii) As a Businessman:  - Standard office applications, e.g Ms-Word, reports etc. Spreadsheets e.g MS Excel: Analyse Financial Information, calculations etc.  - Database software: e.g Oracle, Microsoft SQL Server, Access, managing data in many forms etc.  - Presentation Software, e.g Newsletters, Magazines , etc.  - Graphics Software, e.g Adobe Photoshop, create and edit images such as logs, drawings or picturing.  - Specialist application   - Accounting application.    (iii) As a Banker:  - It is used for an Automated Teller Machine   - Cashline Machine  - For clearing cheques  - For Electronic Transfer (EFT)  - Smart card     (iv) As a Manufacturer:  - Enhances the automation.  - Smart Sensor System for processing and control and lobotics within the food process chain.  - Enhances effective communication.    (v) As a Teacher: It has:-  - Enable teachers to transform their teaching practices.  - Improves the nature through which teaching/ICT use impacts on students achievement.  - Lesson planning is crucial when using ICT.  - It is a tool that helps teachers create more learnercentric learning environment.  - Use to support change and to support/extend existing teaching practices.  - For information presentation.", "marks": "20", "difficulty": "3"}, {"id": "theory>Data Processing>2019>3>a", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "A secondary school has over twenty personal computers. The school management intends to connect all the computers in a network.  Give four reasons that must have motivated the school management into connecting the computers together.", "images": [], "marking_scheme": "Reasons that Might Motivate the School Management into Connecting the Computers Together are:  - To enhance communication and availability of information.  - It allows for more convenient resource sharing.  - It makes file sharing easier.  - It is highly flexible.  - It is an inexpensive system.  - It increases cost efficiency.  - It boosts storage capacity.", "marks": "8", "difficulty": "2"}, {"id": "theory>Data Processing>2019>3>b", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "List four network devices required to accomplish the task in 3(a).", "images": [], "marking_scheme": "Network Devices Required to Accomplish the Task in 3(a)  - Computer system  - Network cable  - Network interface card  - HUP  - Switch  - Router  - Firewall  - Modem    Network Cable: It is a device that enables a computer to be connected to the network.    Network Interface Card:  - It controls the wired and wireless connections of a computer to exchange information with other computers.  - It connects the computer to a local data network.  - It enables computer to communicate with one another.  - It serves as a mediator for network and computer.    Hub: - Use to connect segments of a LAN.  - Connect multiple computers or other network devices together.    Switch:  - As access or OS 1 layer 2.  - For connecting multiple hosts (PCs).  - Forward a message to a specific host.    Router:  - Connecting multiple networks and forward packets destined either for its own networks or other networks.  - It acts as an intersection between multiple IP networks.  - It determines the best path based on the destination MAC address.  - It forwards data packets toward their destination.    Proxy Server:  - Verifies and Forwards incoming client request to other server for further communication.  - Acts as an intermediary between the web browser and the web server.  - Provides internal system security.  - Speeds up resource access.  - To circumvent regional restrictions.    Network Bridge:   - Connects two segments of a network together.  - Divides network into manageable sections.    Firewall:  - Protects networks or network devices.  - Filters packets.  - Prevents network traffic.  - Inspects packets which is supposed to forward, to determine whether they correspond, to a desired template for traffic patterns.    Modem:   - Converts digital signals generated by the computer into analog signals.  - Modulates signals.  - Data compression  - Error correction  - Flow control", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2019>3>c", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "State one function each for any two of the devices listed in 3(b).", "images": [], "marking_scheme": "Network Devices Required to Accomplish the Task in 3(a)  - Computer system  - Network cable  - Network interface card  - HUP  - Switch  - Router  - Firewall  - Modem    Network Cable: It is a device that enables a computer to be connected to the network.    Network Interface Card:  - It controls the wired and wireless connections of a computer to exchange information with other computers.  - It connects the computer to a local data network.  - It enables computer to communicate with one another.  - It serves as a mediator for network and computer.    Hub: - Use to connect segments of a LAN.  - Connect multiple computers or other network devices together.    Switch:  - As access or OS 1 layer 2.  - For connecting multiple hosts (PCs).  - Forward a message to a specific host.    Router:  - Connecting multiple networks and forward packets destined either for its own networks or other networks.  - It acts as an intersection between multiple IP networks.  - It determines the best path based on the destination MAC address.  - It forwards data packets toward their destination.    Proxy Server:  - Verifies and Forwards incoming client request to other server for further communication.  - Acts as an intermediary between the web browser and the web server.  - Provides internal system security.  - Speeds up resource access.  - To circumvent regional restrictions.    Network Bridge:   - Connects two segments of a network together.  - Divides network into manageable sections.    Firewall:  - Protects networks or network devices.  - Filters packets.  - Prevents network traffic.  - Inspects packets which is supposed to forward, to determine whether they correspond, to a desired template for traffic patterns.    Modem:   - Converts digital signals generated by the computer into analog signals.  - Modulates signals.  - Data compression  - Error correction  - Flow control", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2019>4>a>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Explain this database management term:    entities", "images": [], "marking_scheme": "An entity is an object in the system that we want to model and store information about. Entities are usually recognisable concepts either concrete or abstract such as person, places, things or events which have relevance to the database.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2019>4>a>ii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Explain this database management term:  attributes", "images": [], "marking_scheme": "- It is a database component such as a table, it is also seen as a database field, they describe the instances in the row of a database. OR It is a column or field in a database table, e.g given a customer table, a name column.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2019>4>a>iii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Explain this database management term:  relationships", "images": [], "marking_scheme": "A relationship in the context of database is a situation that exists between two relational database tables when one table has a foreign key that references the primary key to the other table. Relationship allows relational databases to split and store data in different tables, while linking disparate data items.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>4>b>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Define cardinality in database management.", "images": [], "marking_scheme": "Cardinality: Refers' to the uniqueness of data values contained in a column. High cardinality means that the column contains a large percentage of totally unique values.  lot of \"repeals\" in its data range.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>4>b>ii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Mention three cardinality relationships in database management.", "images": [], "marking_scheme": "- One-to-one (1:1) relationship  - One-to-many (1:) relationship  - Many-to-many (M:M) relationship", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>5>a>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure I illustrates a part of a computer system,    Identify the part labelled Y.", "images": ["Data Processing/imgs/2019/img1.png"], "marking_scheme": "Disk drive", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2019>5>a>ii>I", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "I", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure I illustrates a part of a computer system,   State:  - the technology used in the part labelled Z.", "images": ["Data Processing/imgs/2019/img1.png"], "marking_scheme": "- The technology used in the part labelled z is disk (compact disk).", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2019>5>a>ii>II", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "II", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure I illustrates a part of a computer system,   State:  - the function of the part labelled X.", "images": ["Data Processing/imgs/2019/img1.png"], "marking_scheme": "- - x - for switching on and off.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2019>5>a>ii>III", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "III", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Figure I illustrates a part of a computer system,   State:  - one maintenance practice for the part labelled Z.", "images": ["Data Processing/imgs/2019/img1.png"], "marking_scheme": "- Always clean the surface with white clean cloth.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2019>5>b", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 2 shows a setup of a computer system.  State one function of each of the parts labelled P, Q, R, S and T.  P: _________  Q: _________ R: _________ S: ___________ T: _________", "images": ["Data Processing/imgs/2019/img2.png"], "marking_scheme": "P - It is used to view/see what the computer is doing.  Q - It is the system unit where the computer memory is located.  R - It is used to move round the screen of the monitor, it is used to give command to the computer.  S - It is used to type/send in data into the computer.  T - It is used to store data that can be used on any computer system.", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2019>5>c>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Outline the steps taken to perform this task in Corel Draw application:    insert a circular shape;", "images": [], "marking_scheme": "- Hold down Ctrl and drag in the drawing window until the circle is the size you want.  - In the box, click the 3-point ellipse tool in the drawing window, drag to draw the central line of the ellipse at the angle you want.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>5>c>ii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Outline the steps taken to perform this task in Corel Draw application:  add the caption \"Happy Birthday\" around the circular shape and change the colour of the caption to green.", "images": [], "marking_scheme": "- Select the circular shape and the caption \"Happy Birthday\" using the pick tool.  - Click on text menu and select \"fit to path\".   OR  - Select the caption using the pick tool and click on text menu.  - Click on fit to path and click on the circular shape.    Changing the colour of the caption to green.  - Select the caption and use the interactive fill tool or the mesh fill.  - Choose the colour you want and click.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>6>a>i", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Table 1 shows the list of items and the quantity of the item needed by a student. The table was created on an MS Excel worksheet.  Use the table to answer this question  Table 1  ITEMQUANTITYTextbook  Biro  Exercise Book  Pencil  Calculator  Eraser12  5  18  3  2  2  Outline the steps to:    create a bar chart on the worksheet such that the items would be labeled on the chart and the percentage of each item included.", "images": [], "marking_scheme": "Type/Create the Table with the Values Needed for the Chart  - Highlight the datas   - On the menu bar click on insert and select the type of bar chart design you want and click.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>6>a>ii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Table 1 shows the list of items and the quantity of the item needed by a student. The table was created on an MS Excel worksheet.  Use the table to answer this question  Table 1  ITEMQUANTITYTextbook  Biro  Exercise Book  Pencil  Calculator  Eraser12  5  18  3  2  2  Outline the steps to:  add to the table, a new; A. column: B. row.", "images": [], "marking_scheme": "To Add a New Row:  - Pick a cell or row that's not the header row and right click.  - Point to insert and pick table rows above to insert a new row.    To Add a New Column:  - Pick any cell in the table and right click.  - Point to insert table column to the left to insert a new column.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>6>a>iii", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Table 1 shows the list of items and the quantity of the item needed by a student. The table was created on an MS Excel worksheet.  Use the table to answer this question  Table 1  ITEMQUANTITYTextbook  Biro  Exercise Book  Pencil  Calculator  Eraser12  5  18  3  2  2  Outline the steps to:  State one function in MS Excel that can be used to determine the item with the highest quantity.", "images": [], "marking_scheme": "Max formula: Returns the largest value from the numbers provided.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2019>6>b", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Outline the steps to add page border to a document using Art Design Tool in MS Word application.", "images": [], "marking_scheme": "How to Create a Page Border in Microsoft Word:  - Open Microsoft word.  - Click on the page layout tab.  - In the page layout background group, click the page border options.  - In the border and shading window, click the page border tab.  - Select box if you want a square border around your page.  - Select the style of border you want on the page which can be solid, dotted or dashed.  - Click the OK button to apply the border.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2019>6>c", "subject": "Data Processing", "year": "2019", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "An MS Word document contains the phrase \"WAEC Exam\". Highlight the steps to link the phrase above to the WAEC website, (http://www.waec.org.ng)", "images": [], "marking_scheme": "- Go to the webpage to which you want to link in order to find the link for a website specific page, you must go to the page first.  - Select the webpage's address the top of the web browser.  - Copy the address  - Find a place to post the link.  - Paste your link.  - Test your link.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2020>1>a", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "What is a function in MS Excel?", "images": [], "marking_scheme": "A function in MS Excel is a predefined formula that performs calculations using specific values in a particular order.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2020>1>b", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "List two categories of functions in MS Excel?", "images": [], "marking_scheme": "- Compatibility  - Database", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2020>1>c", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "What is cell referencing in MS Excel?", "images": [], "marking_scheme": "A cell referencing in Excel refers to the value of a different cell or cell range on the current worksheet or a different worksheet within the spreadsheet.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2020>1>d>i", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "State two types of cell referencing in MS Excel", "images": [], "marking_scheme": "- Relative reference  - Absolute reference", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2020>1>d>ii", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Give one example of each type in 1 (d) (i)", "images": [], "marking_scheme": "- Relative: G2*H2  - Absolute : $A$2", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2020>2>a", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Ciroma Chukwuma Adekunle has just opened a computer business centre within a school environment    State three computer services that may be provided in the business centre", "images": [], "marking_scheme": "- Photocopying  - Scanning  - Printing", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2020>2>b", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Ciroma Chukwuma Adekunle has just opened a computer business centre within a school environmentState three things he needs for the business", "images": [], "marking_scheme": "- Computer system  - Scanning  - Printer", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2020>2>c", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM~~TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE~~TOOLS FOR PROCESSING INFORMATION : SPREADSHEET~~TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Ciroma Chukwuma Adekunle has just opened a computer business centre within a school environmentGive two application software needed in the business centre", "images": [], "marking_scheme": "- Microsoft Office  - Microsoft Excel", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2020>2>d", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Ciroma Chukwuma Adekunle has just opened a computer business centre within a school environmentOutline two precautions that must be taken by Ciroma Chukuma Adekunle to ensure the safety of his computers if he must accept document devices from his customers", "images": [], "marking_scheme": "- He should make sure his anti- virus is up to date  - He should use USB Disk security always", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2020>3>a>i", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "State the keyboard shortcut keys to:    rotate an object in CorelDraw", "images": [], "marking_scheme": "Press Ctrl +, (comma) while nothing is selected (i.e select Pick tool and click on blank place and then press CTRL +, and then you have permanetly set up default angle to \"0\".", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2020>3>a>ii", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "State the keyboard shortcut keys to:Position an object in CorelDraw", "images": [], "marking_scheme": "- Align Right : R  - Align left: L  - Align Center Vertically: C  - Align Center Horizontally: E", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2020>3>a>iii", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "State the keyboard shortcut keys to:Navigate to cell A in MS Excel worksheet", "images": [], "marking_scheme": "Hold down the Ctrl + Home keys together as following screenshot shown, the cursor will be jump to the cell A1 from anywhere of the worksheet.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2020>3>b", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Give one reason for including the plus sign(+) in the search space of a search engine", "images": [], "marking_scheme": "- It tells google or any search engine to find the exact format.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2020>3>c", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "c", "group": "", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "With the aid of diagram, differentiate between LAN and WAN", "images": ["Data Processing/imgs/2020/sscedata2020the3c.png"], "marking_scheme": "A LAN (local area network) is a group of computers and network devices connected together, usually within the same building. By definition, the connections must be high speed and relatively inexpensive (e.g., token ring or Ethernet). Most Indiana University Bloomington departments are on LANs. A LAN connection is a high-speed connection to a LAN. On the IUB campus, most connections are either Ethernet (10 Mbps) or Fast Ethernet (100 Mbps), and a few locations have Gigabit Ethernet (1000 Mbps) connections.  A WAN (wide area network), in comparison to a MAN, is not restricted to a geographical location, although it might be confined within the bounds of a state or country. A WAN connects several LANs, and may be limited to an enterprise (a corporation or an organization) or accessible to the public. The technology is high speed and relatively expensive. The Internet is an example of a worldwide public WAN.", "marks": "5", "difficulty": "3"}, {"id": "theory>Data Processing>2020>4>a>i", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "A school decides to harmonize the operation of its two compuses using a distributed database system as well as install air conditioners and uninterrupted power supply in the computer laboratory    State three:    - importance of using the distributed database system", "images": [], "marking_scheme": "- Its ability to replicate data automatically helps in data recovery if database in any site is damaged  - When a component fails,the functioning of the system continue may be at a reduced performance, hence, making it reliable  - It has a lower communication cost", "marks": "7", "difficulty": "3"}, {"id": "theory>Data Processing>2020>4>a>ii", "subject": "Data Processing", "year": "2020", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES~~ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "A school decides to harmonize the operation of its two compuses using a distributed database system as well as install air conditioners and uninterrupted power supply in the computer laboratory    State three:disadvantages of using computers to process information in the school", "images": [], "marking_scheme": "- Constant use of computers to process information in school will make students technological dependent  - Deterioration of the teacher role in the learning process  - Excessive individualization of learning due to computer usuage can lead to denial of the teacher  - Use of computer which may hinder step by step students mental activity by the teacher stops them from developing creative abilities and entrepreneur spirit and initiative.", "marks": "8", "difficulty": "3"}, {"id": "theory>Data Processing>2021>1>a>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Define the following terms:    - disk formatting", "images": [], "marking_scheme": "Disk formatting is the configuring process of a data storage media such as gard disk drive, floppy disk or flash drive for initial usage.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>1>a>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Define the following terms:    - data backup", "images": [], "marking_scheme": "Data backup is a copy of computer data taken and stored elsewhere so that it may be used to restore the original after a loss event.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>1>a>iii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Define the following terms:    - virus scan", "images": [], "marking_scheme": "Virus scan is the process where antivirus search through your system to locate and remove any malicious threats on your device.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>1>b", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "state four uses of the Automated Teller Machine(ATM)", "images": [], "marking_scheme": "- It is used for intra bank transfer   - It is used for inter bank transfer   - It is used to check account balance   - It is used for printing of mini statement of account   - It is used for bank withdrawal", "marks": "8", "difficulty": "2"}, {"id": "theory>Data Processing>2021>2>a", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Complete Table with the appropriate critteria for each storage medium     Criteria Medium\tDVD-ROM\tHard Disk\tMagnetic Tape\tLocation of storage device\tExternal\t(i).......................\t(ii)........................\tRemovability\t(iii).............................\t(iv)..........................\t(v).....................\tMethod of files Acess\t(vi)....................\tRandom/Direct Acess\t(vii)....................", "images": [], "marking_scheme": "Criteria Medium\tDVD-ROM\tHard Disk\tMagnetic Tape\tLocation of storage device\tExternal\t(i)Removable\t(ii)Indirect access\tRemovability\t(iii) Internal\t(iv)Not removable\t(v)Ramdom/Direct access\tMethod of files Acess\t(vi) External\tRandom/Direct Acess\t(vii)External", "marks": "7", "difficulty": "3"}, {"id": "theory>Data Processing>2021>2>b", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "List three examples of spreadsheet applications", "images": [], "marking_scheme": "- Google Sheets   - Lotus Symphony   - Microsoft Excel   - Open office   - libre Office   - Lotus 1-2-3", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>3>a>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "State three ways of classifying computers", "images": [], "marking_scheme": "- On the Basis of Size and Capacity: Supercomputer, Mainframe, Mini and Micro Computer     - On the Basis of Purposes: General and Special purpose Computer     - On the Basis of Hardware Design and Type: Analog, Digital and Hybrid Computer", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>3>a>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Differentiate between digital and analog computers", "images": [], "marking_scheme": "- Analog computers works with continuous values or these types of system process continuous data. Analog computer has vey low or limted memory and it can store less amount of data.     - Digital computers works with discrete values or these types of systems process discrete data. Digital computer has very big memory and it can store large amount of data.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>3>b", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "List three positive impacts of ICT on the society", "images": [], "marking_scheme": "- Access to information   - New tools , new opportunities   - Communication", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>3>c", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Give two types of information transmission medium", "images": [], "marking_scheme": "- Guided Media   - Shielded Twisted Pair (STP)", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2021>4>a", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "A certain business centre provides computer and internet services to the public, concerned that there is no restraint on consumption of food and drinks by the customer, also about health hazards to the computer users.    Give two safety precautions that must be put in place to protect the works business centre from foods and drinks", "images": [], "marking_scheme": "- designing and implementing safeguards to control the risks     - Overseeing and handling practices of services.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>4>b", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "A certain business centre provides computer and internet services to the public, concerned that there is no restraint on consumption of food and drinks by the customer, also about health hazards to the computer users.    State two ways the computers can be maintained to ensure efficiency in service", "images": [], "marking_scheme": "-protect with padding   - Organize cords   - Update your operating system   - Unplug to avoid overcharging   - run regular antivirus scans", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>4>c>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "A certain business centre provides computer and internet services to the public, concerned that there is no restraint on consumption of food and drinks by the customer, also about health hazards to the computer users.    Name three possible health risks to the customers while using the computer centre", "images": [], "marking_scheme": "- Photosensitive epileptic seizures     - Injuries from laptop computers     - Eyestrain from computer use", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2021>4>c>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "A certain business centre provides computer and internet services to the public, concerned that there is no restraint on consumption of food and drinks by the customer, also about health hazards to the computer users.    How can the risks in 4(c)(i) be reduced?", "images": [], "marking_scheme": "- identifying internal and external risks to the security, confidentiality and integrity of your customer's personal information     - designing and implementing safeguards to control the risks     - periodically monitoring and testing the safeguards to be sure they are working effectiviely.", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2021>5>a", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A student was given as assignment which involved typesetting a passage at home using a computer. The student was required to bring the soft copy of the assignment in a flash drive volume label STUDENT_ ASSIGNMENT to the school.  Highlight the steps the student would take to:    save the typeset work in the flash drive;", "images": [], "marking_scheme": "- Insert the flash drive into a usb port on your computer   - With your microsoft word document open, click the file :tab and select :save as.\"   - Click the \"save in\" drop-down menu at the top of the save as dialog box.   - Navigate to and click the flash drive. The flash drive is typically drive letter \"e\" or \"f\".   - Type the name of your document into the file name field and click \"save' to save the file to the flash drive.", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2021>5>b", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A student was given as assignment which involved typesetting a passage at home using a computer. The student was required to bring the soft copy of the assignment in a flash drive volume label STUDENT_ ASSIGNMENT to the school.  Highlight the steps the student would take to:   - create a folder named ASSIGNMENTS on the desktop of a computer in the school's computer laboratory and save the typeset assignment in the folder.", "images": [], "marking_scheme": "- Navigate to the location where you want to create the folder that is the desktop of the computer   - Hold down the crtl, shift and n keys at the same time.   - Enter your desired folder name that is \"assignment\"   - Navigate to the location where you want to create the folder   - Then save to finish.", "marks": "10", "difficulty": "1"}, {"id": "theory>Data Processing>2021>5>c", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A student was given as assignment which involved typesetting a passage at home using a computer. The student was required to bring the soft copy of the assignment in a flash drive volume label STUDENT_ ASSIGNMENT to the school.  Highlight the steps the student would take to:   - print the assignment from the folder created in 5(b)", "images": [], "marking_scheme": "- Open the folder that contains the word documents you wnat to print   - Press {crtl}, and select the files you wan to print. (if the files are adjacent, select the first file in the list, press[shift], and select the last file un then list).   - Right-click the selection, and select print from the shortcut menu   - Select the desired print options, and click ok.(the selected options will apply to all of the documents.)", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2021>6>a>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List    - two biometric data capturing devices at the data entry point", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "- Finger print   - Facial Geometry Recognition", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>a>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List   - two transmission media for sending the output to the internet", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "- Modems   - Multiplexers", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>a>iii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List   - one output device to give out audio from the system", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "RCA (Stereo audio output)", "marks": "1", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>a>iv", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "iv", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List   - two types of data that can can be viewed in the display", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "- Finger print   - Signature", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>b>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List    Give one: difference between information stored in the part labelled storage and the part labelled internet in terms of acess", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "Difference is that to access that on the internet, it requires an Internet Service Provider(ISP) and a router to connet to the ISP while it is not needed for that of storage.", "marks": "0.5", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>b>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List   Give one: reason the biometric data is foot proof", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "Biometric recognition creates a specific link between an individuall and a data record.", "marks": "0.5", "difficulty": "2"}, {"id": "theory>Data Processing>2021>6>c", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Above diagram shows the schematic procedure of an information processing system.   System are biometric based data as other details had been captured. Use the figure in the questions below   List    - if data already captured into the system include: student's scores, date of origin and age; outline the two operations possible at the processing unit.", "images": ["Data Processing/imgs/2021/img18.png"], "marking_scheme": "- Data collection   - Data input", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2021>6>d>i", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Diagram below represents the interface of an application software. Use the figure to answer questions below         State one:    - use of the parts labelled I to V;", "images": ["Data Processing/imgs/2021/data6di.png"], "marking_scheme": "- To: Email address   - CC: To send to multiple Email   - BCC: When you wnat the message to be shared, but you want to keep it secret to who gets the message.   - To the reader   - The content of the message", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2021>6>d>ii", "subject": "Data Processing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Diagram below represents the interface of an application software. Use the figure to answer questions below         State one:   - difference between the parts labelled II and III", "images": ["Data Processing/imgs/2021/data6di.png"], "marking_scheme": "- Cc stands for carbon copy which means that whose address appears after Cc:header would receive a copy of the message. Also, the Cc header would also appear inside the header of the received message     - While Bcc stands for blind carbon copy which is similar to that of Cc except that the Email address of the recipients in the To or Cc fields will not know that a copy sent to these address.", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2022>1>a", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Define information transmission", "images": [], "marking_scheme": "Information transmission is the exchange of information in any form ( e.g voice, data, text and images) over a medium (air, cable ,water ,) using natural, or man- made equipment or tools.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2022>1>b>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Differentiate between:    internet and intranet;", "images": [], "marking_scheme": "Internet IntranetInternet is a huge network that connects computer networks across the world. It uses the Internet protocol suite (TCP/IP) An intranet is a network connection similar to the internet but it is limited by the users within an organization. It can include several LANs or leased lines in the wide-area network.The internet enables the exchange of a huge amount of (unlimited) information between the connected users. It enables the exchange of limited information between limited and authorized people of a particular firm.It provides access to all types of information. The intranet has all the information, resources, programs, events, and more related to a company.It is a public network. It is a private network.The internet has multiple users. Anyone can access it. Intranet has are limited users. Only certain people with login credentials are authorized to use Intranet.The Internet consists of several intranets. It is like a part of the Internet.It is a wide and insecure network. Internet is a global network with low privacy. There is the possibility of leaks of data and information. Intranet is a limited and secure network. It has a pre-installed firewall that protects the privacy of the firm against unauthorized access or hackers.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2022>1>b>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Differentiate between: LAN and WAN", "images": [], "marking_scheme": "LAN WANLAN stands for Local Area Network WAN stands for Wide Area Network.LAN's ownership is private. WAN's ownership can be private or public.The speed of LAN is high(more than WAN) The speed of WAN is slower than LAN.The propagation delay is short in LAN. Whereas the propagation delay in WAN is long(longer than LAN)LAN operates on the principle of broadcasting. WAN works on the principle of point to point.LANs technologies used like ethernet and token. WANs technologies used like Frame Relay and X.25 for connectivity for longer distances.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2022>1>c", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "List four devices used in a LAN environment", "images": [], "marking_scheme": "- Hub  - Bridge  - Layer 2 Switch  - Layer 2 Switch  - Router", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2022>2>a>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A medium scale enterprise intends to create a database to manage its staff records with the following fields: staff ID, Name, Address, Photograph and Department.    what is database?", "images": [], "marking_scheme": "A database is an organized collection of structured information, or data, typically stored electronically in a computer system.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2022>2>a>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A medium scale enterprise intends to create a database to manage its staff records with the following fields: staff ID, Name, Address, Photograph and Department.List three DBMS the firm can use to achieve the stated objectives", "images": [], "marking_scheme": "- MySQL  - PostgreSQL  - Microsoft SQL Server  - Oracle Database  - Microsoft Access.", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2022>2>b>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "A medium scale enterprise intends to create a database to manage its staff records with the following fields: staff ID, Name, Address, Photograph and Department.    Mention two tasks that can be performed on staff photographs using graphic packages", "images": [], "marking_scheme": "- The dimension of the their photographs can be changed.   - Different adjustments such as the exposure to light, hue and saturation, etc for example can be made.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2022>2>b>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "A medium scale enterprise intends to create a database to manage its staff records with the following fields: staff ID, Name, Address, Photograph and Department.Give three examples of graphic packages that can be used for the tasks above", "images": [], "marking_scheme": "- Ms Paint  - Adobe Photoshop  - Instant artist  - Harvard graphic  - CorelDraw", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2022>3>a>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "What is a presentation package?", "images": [], "marking_scheme": "A presentation package is a software program that contains a text editor and the ability to add charts and graphic images, such as photographs, clip art, or other objects so as to make a slide show for the purpose of communicating visually to an audience.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2022>3>a>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Give two examples of presentation package", "images": [], "marking_scheme": "- Microsoft PowerPoint.  - Macromedia flash.  - Windows movie maker.  - Open Office.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2022>3>a>iii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "State three features of a presentation package", "images": [], "marking_scheme": "- Presentation packages allow you to create or insert slides anywhere in a presentation.  - They are shown on a page-by-page basis, where each page of information is called a slide.  - Pictures, images, video and audio files can be inserted into slides.  - Inserted slides can easily be deleted.  - Slides can be cut and pasted in any order.  - You can display presentation designed in the slide show systems  - Presentation packages allow animations and sound manipulation on objects in a slide", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2022>3>b", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Highlight the steps followed to find and replace data in MS Excel", "images": [], "marking_scheme": "- Press Ctrl+H or go to Home > Find & Select > Replace.  - In Find what, type the text or numbers you want to find.  - You can further define your search: ...  - In the Replace with box, enter the text or numbers you want to use to replace the search text.  - Select Replace or Replace All", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2022>4>a", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A professional photographer uses analogue cameras and a computer system for his business. The computer is used to prepare documents and keep records of clients' account. Copies of these documents are stored in CD-ROMs and Floppy disks. The photographer now plans to innovate by using digital cameras and the computer for taking, editing and printing photographs.    State two hardware changes required on the photographer's computer to achieve the planned innovation", "images": [], "marking_scheme": "- A coloured printer connected to the Computer System.   - The use of a USB cable to transfer the digital images from the camera to the computer system.", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2022>4>b>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A professional photographer uses analogue cameras and a computer system for his business. The computer is used to prepare documents and keep records of clients' account. Copies of these documents are stored in CD-ROMs and Floppy disks. The photographer now plans to innovate by using digital cameras and the computer for taking, editing and printing photographs.Give one reason:  for each of the changes above", "images": [], "marking_scheme": "- transfer of the images file  - to print edited pictures/images from the computer system", "marks": "4", "difficulty": "3"}, {"id": "theory>Data Processing>2022>4>b>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A professional photographer uses analogue cameras and a computer system for his business. The computer is used to prepare documents and keep records of clients' account. Copies of these documents are stored in CD-ROMs and Floppy disks. The photographer now plans to innovate by using digital cameras and the computer for taking, editing and printing photographs.why the photographer should use external hard disk instead of floppy disk to store data", "images": [], "marking_scheme": "The hard disk provides for larger storage capacities and much faster access time as compared to floppy disk", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2022>4>c", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "State two advantages of switching from analogue to digital camera", "images": [], "marking_scheme": "- The photographs of customers can be saved for future purposes.  - The quality of the pictures will improve.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2022>5>a", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address    Highlight the procedures the captain will follow to create the database", "images": [], "marking_scheme": "Steps   1. Open Microsoft Access   2. Select \"Blank database\"  3. Enter \"Student_Record\" as the name of the database, select a location and then select create   4. Click on file > open and select the database \"Student_Record\" if not already opened, and click \"open\"", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2022>5>b", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  List the steps the captain would take to create the table in Design View", "images": [], "marking_scheme": "1. Click on create tab    2. Click Table design    3. Enter a field name in the field Name column and press enter     4. Click on Data type list arrow and select a data type for the field .    5. Type name of the field    6.Repeat 3 to 5 to add more fields    7 after adding fields click on close button and click yes to save changes    8. Enter \"Students\" as table name to save table.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2022>5>c", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "c", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  Give the data type suitable for each column/field provided", "images": [], "marking_scheme": "Data type for each entry     ID_Number - Number/AutoNumber     Full Name - Short Text (Formally known as Text )    Date of Birth - Date & Time     Age  -  Number/ Calculated     Home Address - Text", "marks": "5", "difficulty": "2"}, {"id": "theory>Data Processing>2022>5>d", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "d", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  Which field can be used as the primary key?", "images": [], "marking_scheme": "ID_Number is unique, hence can be used as the primary key", "marks": "1", "difficulty": "2"}, {"id": "theory>Data Processing>2022>5>e", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "e", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  Mention one  importance of primary keys", "images": [], "marking_scheme": "- Since the primary key serves as an index, speed-based database operations like sorting and searching for records becomes faster.  - The primary key helps to quickly identify and find unique rows in a particular database table.  - In safe mode, only specific records can be uniquely identified using the primary key to ensure that updates and deletion only affect specific rows rather than larger volumes of data.   - Primary keys are used to easily identify a data entry or data from a table or multiple tables and combine the data in a powerful way     - Also primary key serves as an index to enable quick searching    - Primary key helps to quickly identify unique rows", "marks": "1", "difficulty": "2"}, {"id": "theory>Data Processing>2022>5>f", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "f", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  List three SQL command statements the class captain can perform on the database", "images": [], "marking_scheme": "Command Statements include  1. SELECT  2. UPDATE  3. DELETE  4. CREATE TABLE  5. INSERT INTO", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2022>5>g", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "g", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A class captain was asked to create a database in MS Access for all the student in the class without using any template and name it Student_Record. The table created is to be named Students and should have five colunms/fields with the following names:  ID_Number  Full Name  Date of Birth  Age  Home_Address  Give the SQL query the captain will use to display all the columns in table Students", "images": [], "marking_scheme": "The SQL query is     \"SELECT * FROM Students\"", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2022>6>a>i", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Outline the steps taken in MS words to:    create a table with 4 columns and 6 rows", "images": [], "marking_scheme": "- Open a blank Word document.  - In the top ribbon, press Insert.  - Click on the Table button.  - Either use the diagram to select the number of columns and rows you need, or click Insert Table and a dialog box will appear where you will input 4, in the number of columns and 6 as the number of rows.  - The blank table will now appear on the page.", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2022>6>a>ii", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Outline the steps taken in MS words to: insert a hyperlink on a text", "images": [], "marking_scheme": "Select the text that you want to display as a hyperlink. Press Ctrl+K. You can also right-click the text and click Link on the shortcut menu. In the Insert Hyperlink box, type or paste your link in the Address box.", "marks": "5", "difficulty": "1"}, {"id": "theory>Data Processing>2022>6>b", "subject": "Data Processing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "State the function of the parts labeled I to V in figure above", "images": ["Data Processing/imgs/2022/dataprocessingtheory.jpg"], "marking_scheme": "I - To align a text or paragraph to the left or make a text or paragraph left- aligned or to the left side margin of a Microsoft page. Also called left-Align    II - To align a text or paragraph to the centre of a word document. Also called Center -Align     III -  To align a text or paragraph to the right of a word document or the right side margin of a Microsoft page.  Also called Right- Align     IV -  To justify a text or paragraph. A paragraph or text is said to be justified when it is aligned evenly along both the left and right side margins of the page in ms-word     V - To adjust the space between lines in a text or paragraph. It is also called line -spacing", "marks": "10", "difficulty": "2"}, {"id": "theory>Data Processing>2023>1>a", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "State one function for each of the following utility program    Disk space analyzer", "images": [], "marking_scheme": "- Visualize disk space usage: A disk space analyzer can help to visualize how the disk space is being used by displaying a graphical representation of the size of each file and folder. This can be helpful for identifying which files or folders are taking up the most space on the disk.    - Find large files: A disk space analyzer can also help to find large files that one may not be using anymore. This can be helpful for freeing up disk space by deleting these files.    - Identify duplicate files: A disk space analyzer can also identify duplicate files on the disk. This can be helpful for deleting duplicate files, which can free up a lot of disk space.    - Analyze disk usage trends: A disk space analyzer can also analyze disk usage trends over time. This can be helpful for identifying patterns in the disk usage and making informed decisions about how to manage the disk space.    - Generate reports: A disk space analyzer can generate reports that summarize the disk space usage. These reports can be helpful for sharing with others or for tracking the disk space usage over time.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>1>b", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "State one function for each of the following utility program  Backup utility", "images": [], "marking_scheme": "- Create backups of data: A backup utility can create backups of data, which can be used to restore the data in the event of a disaster, such as a hard drive failure or a cyberattack.    - Schedule backups: A backup utility can be scheduled to automatically create backups at regular intervals, such as daily, weekly, or monthly. This can help ensure that the data is always backed up up-to-date.    - Encrypt backups: A backup utility can encrypt the backups to protect them from unauthorized access. This is especially important if one is backing up sensitive data, such as financial information or personal health records.    - Compress backups: A backup utility can compress the backups to reduce the amount of storage space they require. This can be helpful if one is backing up a large amount of data.    - Store backups on multiple locations: A backup utility can store backups on multiple locations, such as an external hard drive, a network drive, or the cloud. This can help protect data from a single point of failure.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>1>c", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "State one function for each of the following utility program  Register cleaner", "images": [], "marking_scheme": "- Remove unused and invalid registry entries: A registry cleaner can remove unused and invalid registry entries from computers. These entries can slow down computers and cause errors.    - Fix corrupted registry entries: A registry cleaner can fix corrupted registry entries from computers. These entries can also slow down computers and cause errors.    - Optimize the registry: A registry cleaner can optimize the registry, which can improve the performance of the computer.    - Back up the registry: A registry cleaner can back up the registry before making any changes. This is important in case something goes wrong, one can restore the registry to its original state.    - Scan for malware: Some registry cleaners can also scan for malware in the registry. This can help protect computers from malware infections.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>1>d", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "State one function for each of the following utility program  File manager", "images": [], "marking_scheme": "- Create, delete, and rename files and folders: A file manager allows users to create, delete, and rename files and folders on the computer. This can be helpful for organizing files and folders.    - Copy, move, and paste files and folders: A file manager allows users to copy, move, and paste files and folders between different locations on the computer. This can be helpful for transferring files and folders to different devices or for backing up files.    - Search for files and folders: A file manager allows users to search for files and folders on the computer by name, date, size, or other criteria. This can be helpful for finding files that have been lost or forgotten about.    - View the properties of files and folders: A file manager allows users to view the properties of files and folders, such as their size, creation date, and modification date. This can be helpful for getting information about files and folders.    - Compress and decompress files: A file manager can compress and decompress files, which can help users save space on the computer.    - Encrypt and decrypt files: A file manager can encrypt and decrypt files, which can help users protect their files from unauthorized access.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>1>e", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "e", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "State one function for each of the following utility program  Uninstaller", "images": [], "marking_scheme": "- Remove programs from the computer: An uninstaller can remove programs from the computer, including all of the files, folders, and registry entries that the program created. This can be helpful for freeing up disk space and for preventing problems caused by orphaned files and registry entries.    - Safely uninstall programs: A good uninstaller will uninstall programs safely and completely, without leaving behind any residual files or registry entries. This can help protect computers from problems caused by incomplete uninstalls.    - Uninstall programs that are not uninstallable: Some programs do not come with uninstallers, or the uninstallers that they do come with are not effective. An uninstaller can help to uninstall these programs safely and completely.    - Uninstall programs in bulk: If one has a lot of programs that one wants to uninstall, an uninstaller can help to uninstall them in bulk, which can save time.    (v) Uninstall programs from a remote computer: If one needs to uninstall a program from a computer that one do not have physical access to, an uninstaller can help to do this remotely.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>2>a>i", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "What is malware in computing?", "images": [], "marking_scheme": "Malware, short for \"malicious software,\" refers to any software or code specifically designed to harm, disrupt, or gain unauthorized access to computer systems, networks, or user data. Malware is created with malicious intent and can take various forms, often causing harm to computers, stealing sensitive information, or compromising system integrity. It's a broad category that encompasses a range of malicious software types, each with its own distinct behavior and purpose.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>2>a>ii", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "List three types of malware", "images": [], "marking_scheme": "Common types of malware include viruses, worms, trojans, spyware, adware, ransomware, and more.    Here's a brief overview of some common types of malware:    - Viruses: Viruses are malicious programs that attach themselves to legitimate files or software and replicate when the infected file is executed. They can spread across systems and cause damage by corrupting or deleting files, as well as by spreading to other devices.    - Worms: Worms are self-replicating malware that spread through computer networks without requiring user interaction. They exploit vulnerabilities to automatically infect and spread to other systems, often causing network congestion and slowdowns.    - Trojans: Trojans, named after the deceptive Trojan Horse from Greek mythology, appear to be legitimate software but contain hidden malicious functions. They can create backdoors, steal information, or perform other harmful actions.    - Spyware: Spyware is designed to collect information from a user's device without their knowledge. It can track browsing habits, capture keystrokes, record personal information, and relay this data to malicious actors.    - Adware: Adware displays unwanted advertisements to users, often in the form of pop-ups or banners. While not always harmful, adware can be intrusive and negatively affect the user experience.    - Ransomware: Ransomware encrypts a user's files or entire system and demands payment (a ransom) in exchange for the decryption key. It can render data inaccessible until the ransom is paid, though there's no guarantee of receiving the decryption key even after payment.    - Botnets: Botnets are networks of compromised computers, often controlled remotely by a single entity, which can be used for various malicious activities, such as launching distributed denial-of-service (DDoS) attacks or sending spam.    - Rootkits: Rootkits are designed to gain unauthorized access to a computer system and conceal their presence from detection by modifying system components. They often grant control of the system to attackers.    - Keyloggers: Keyloggers capture keystrokes on a compromised system, potentially recording sensitive information like passwords and credit card numbers.    - Malvertising: Malvertising involves spreading malware through online advertisements. Attackers inject malicious code into legitimate ads, and when users click on these ads, they can inadvertently download and install malware.    - Fileless Malware: This type of malware doesn't rely on traditional files but resides in a system's memory or uses legitimate system tools to carry out malicious activities. This makes it harder to detect and remove.    Malware can be introduced through various means, including infected email attachments, malicious downloads, compromised websites, and social engineering tactics. Protecting against malware involves using security software, regularly updating software and operating systems, practicing safe browsing habits, being cautious with email attachments, and regularly backing up important data.", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2023>2>b", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "State three symptoms of malware infection", "images": [], "marking_scheme": "- The computer starts to run slowly. Malware can slow down the computer by consuming resources, such as CPU time and memory.    - The computer crashes or freezes. Malware can cause computers to crash or freeze by overloading it or by corrupting system files.    - One sees new programs or toolbars on the computer. Malware can install new programs or toolbars on the computer without one's knowledge.    - One sees pop-up ads. Malware can display pop-up ads on the computer, even if one have ad blockers installed.    5. The homepage changes. Malware can change the homepage to a website that one did not choose.    6. The search results are different. Malware can change the search results to show websites that are not relevant to the search terms.    7. one receives emails from people one doesn't know. Malware can send emails from one's email account to people one doesn't know.    8. One sees unfamiliar transactions on the bank statement. Malware can steal banking information and make unauthorized transactions.    9. Encrypted files. Ransomware is a type of malware that encrypts files and demands a ransom payment in order to decrypt them.", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2023>2>c", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Give two ways of preventing malware infection", "images": [], "marking_scheme": "One can prevent malware infection by:    - Using Reliable Security Software    - Keeping Software Updated    - Exercising Caution with Email    - Staying Away from Suspicious Websites    - Using Strong and Unique Passwords    - Enabling Firewall Protection    - Being Careful with Downloads    - Regularly Backing Up Data    - Using Secure Wi-Fi Connections    - Disabling Macro Scripts: One should be cautious when enabling macros in documents, as they can be used to deliver malware. Disable macros unless one is sure the document is from a trusted source and requires macros to function properly.    - Educating oneself and Others    - Regularly Scanning for Malware    - Using Browser Security Features    - Patching Software Promptly: Apply updates and patches to software and applications as soon as they're available. Exploits often target known vulnerabilities that can be mitigated with updates.    - Disabling Unnecessary Plugins and Extensions    By implementing these preventive measures, one can significantly reduce the risk of malware infections and maintain a more secure and protected computing environment.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>3>a", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Name two computer professionals that use CorelDraw in the performance of their duties", "images": [], "marking_scheme": "- Graphic Designers: Graphic designers use CorelDRAW to create logos, brochures, posters, banners, business cards, and other visual materials. The software's versatile tools and features make it suitable for both print and digital design projects.    - Illustrators: Illustrators use CorelDRAW to create detailed and intricate illustrations, digital art, and graphics for books, magazines, websites, and various media.    - Web Designers: Web designers use CorelDRAW to design website layouts, user interfaces, icons, buttons, and other graphical elements needed for web development.    - Fashion Designers: CorelDRAW can be used by fashion designers to create fashion illustrations, garment designs, and patterns. Its precision and versatility are valuable in visualizing clothing concepts.    - Packaging Designers: CorelDRAW is employed in designing packaging for products. It allows designers to create 2D and 3D mockups of packaging materials, labels, and boxes.    - Interior Designers: CorelDRAW can be used by interior designers to create floor plans, room layouts, furniture designs, and other visual representations of interior spaces.    - Advertisement Professionals: Professionals in advertising use CorelDRAW to create engaging ad campaigns, including banners, billboards, and other promotional materials.    - Multimedia Artists: Multimedia artists utilize CorelDRAW for creating graphics and visuals for multimedia presentations, animations, video games, and interactive media.    - Architects: Architects can use CorelDRAW for drafting architectural plans, schematics, and diagrams. The software's vector capabilities are useful for creating precise technical drawings.    - Marketing Professionals: Marketing professionals use CorelDRAW to design marketing materials, such as flyers, pamphlets, infographics, and visual content for social media.    - Industrial Designers: CorelDRAW can be used by industrial designers to create product prototypes, schematics, and visualizations of physical objects and products.    - Educators: Educators in design-related fields often teach their students how to use CorelDRAW for various design projects and assignments.    - Signage Designers: Professionals in the signage industry use CorelDRAW to design signs, banners, vehicle wraps, and other visual elements for advertising and information.    These are just a few examples of the types of computer professionals who can use CorelDRAW as a part of their work. The software's versatility makes it a valuable tool in various creative and design-oriented industries.", "marks": "6", "difficulty": "1"}, {"id": "theory>Data Processing>2023>3>b>i", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "List three tools in the CorelDraw toolbox.", "images": [], "marking_scheme": "- Pick Tool    - Shape Tool    - Text Tool    - Node Tool    - Freehand Tool    - Bezier Tool    - Rectangle Tool    - Ellipse Tool    - Polygon Tool    - Star Tool    - Interactive Blend Tool    - Eyedropper Tool    - Interactive Fill Tool    - Knife Tool    - Zoom Tool", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2023>3>b>ii", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Give one function of each tool listed 3(b)(i)", "images": [], "marking_scheme": "- Pick Tool: The Pick Tool is a selection tool used to select and manipulate objects on the canvas. It allows users to move, resize, rotate, skew, and mirror objects, as well as adjust their properties.    - Shape Tool: The Shape Tool enables users to create and modify basic shapes, such as rectangles, ellipses, polygons, and stars. It also provides options for creating custom shapes and modifying corner radii.    - Text Tool: The Text Tool is used for adding and formatting text. Users can create artistic text and paragraph text, adjust font styles, sizes, and colors, and apply various text effects.    - Node Tool: The Node Tool allows users to manipulate individual nodes and control handles of vector objects. It's essential for editing and reshaping paths, curves, and lines.    - Freehand Tool: The Freehand Tool lets users draw freeform lines and shapes by hand, providing control over the smoothness of the curves.    - Bezier Tool: The Bezier Tool is used to create and edit curves using Bezier handles. Users can create smooth and precise curves by manipulating control points.    - Rectangle Tool: The Rectangle Tool creates rectangles and squares. It offers options to create rounded corners and adjust corner radii.    - Ellipse Tool: The Ellipse Tool creates ellipses and circles. It provides options to create perfect circles and adjust the ellipse's aspect ratio.    - Polygon Tool: The Polygon Tool generates polygons with a specified number of sides. Users can adjust the number of sides and other properties.    - Star Tool: The Star Tool creates multi-pointed stars with adjustable properties, such as the number of points, inner and outer radii, and depth.    - Interactive Blend Tool: The Interactive Blend Tool blends or morphs objects between two or more selected shapes, creating smooth transitions and intermediate shapes.    - Eyedropper Tool: The Eyedropper Tool samples colors from existing objects on the canvas, allowing users to apply the sampled color to other objects.    - Interactive Fill Tool: The Interactive Fill Tool applies fills and gradients to objects. It provides interactive controls for adjusting fill properties.    - Knife Tool: The Knife Tool cuts shapes or paths into separate segments. Users can draw custom paths to slice through objects.    - Zoom Tool: The Zoom Tool lets users zoom in and out on the canvas for detailed editing. It offers various zooming options, including zooming to specific areas.    These tools are just a portion of the tools available in the CorelDRAW toolbox. Each tool serves a specific purpose in vector graphic creation and manipulation.", "marks": "7", "difficulty": "2"}, {"id": "theory>Data Processing>2023>3>c", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "State two uses of CorelDraw as an application software.", "images": [], "marking_scheme": "- Graphic Design: CorelDRAW is extensively used for creating graphic designs, including logos, brochures, posters, flyers, business cards, and banners. Its precise vector tools allow designers to create high-quality visuals for both print and digital media.    - Illustration and Artwork: Many illustrators use CorelDRAW to create detailed and intricate illustrations, digital art, and graphics. The software's vector capabilities allow for the creation of scalable and editable artwork.    - Layout Design: CorelDRAW is used for layout design tasks such as creating magazine layouts, book covers, packaging designs, and product labels. Its tools help designers arrange and organize elements effectively.    - Web Design Elements: CorelDRAW is employed to create graphical elements for web design, such as website layouts, icons, buttons, and graphics. These elements can enhance the visual appeal and user experience of websites.    - Typography and Text Design: Designers use CorelDRAW to experiment with typography, create stylized text, and design visually appealing text layouts for various projects.    - Digital Marketing Materials: CorelDRAW is used to design digital marketing materials like social media graphics, online advertisements, and email marketing visuals.    - Vector Tracing and Converting Raster to Vector: The software's tracing capabilities help convert bitmap images (raster) into scalable vector graphics, which is especially useful for creating logos or illustrations from hand-drawn sketches.    - Pattern and Textile Design: CorelDRAW is employed by textile designers to create patterns and designs for fabrics, wallpapers, and other surface materials.    - Architectural and Technical Drawings: Architects and engineers use CorelDRAW for creating technical drawings, schematics, and diagrams. The precise vector tools allow for accurate representations of architectural plans.    - Fashion and Apparel Design: CorelDRAW is used by fashion designers to create fashion illustrations, garment designs, and textile patterns for clothing and accessories.    - Packaging Design: Packaging designers utilize CorelDRAW to design packaging materials, labels, and boxes. The software's tools allow for accurate mockups and presentations.    - Logo Design: CorelDRAW is a popular choice for creating logos due to its vector capabilities, enabling designers to create scalable and versatile logo designs.    - Storyboarding and Comics: Artists and creators use CorelDRAW for storyboarding, comic creation, and visual storytelling, taking advantage of its versatile tools and art capabilities.    - Signage and Large Format Printing: CorelDRAW is used for creating graphics and designs for signage, billboards, vehicle wraps, and other large format printing projects.    - Educational and Learning Materials: CorelDRAW is employed in educational contexts for creating learning materials, diagrams, charts, and other visual aids.    These are just a few examples of the many ways CorelDRAW can be used as an application software across various industries and creative fields. Its features and tools make it a powerful tool for creating a wide range of visual content.", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2023>4>a", "subject": "Data Processing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "With reference to database management system, state:    one difference between fragmentation and replication.", "images": [], "marking_scheme": "In the context of a database management system (DBMS), fragmentation and replication are two strategies used to distribute and manage data across multiple locations or nodes in a distributed database environment. Here are more than one difference between fragmentation and replication:    -  Definition and Purpose:    Fragmentation: Fragmentation involves breaking a database into smaller subsets or fragments that are stored on different nodes. Each fragment may contain a portion of the data or a subset of the database schema. The goal is to divide the data to improve data distribution, access efficiency, and performance.  Replication: Replication involves creating and maintaining duplicate copies of the entire database or portions of it on different nodes. The purpose is to enhance data availability, fault tolerance, and read performance by allowing multiple nodes to access the same data.    - Data Distribution:    Fragmentation: Fragmentation divides the data horizontally (rows) or vertically (columns) among different nodes. Different fragments may contain different rows or columns, reducing the amount of data stored on each node.  Replication: Replication involves creating identical copies of the same data on multiple nodes. All replicated copies contain the same data, which can improve data availability and reduce data access latency.    - Data Consistency:    Fragmentation: Fragmentation may lead to data consistency challenges, especially if updates affect data distributed across multiple fragments. Synchronization mechanisms are needed to ensure consistency.  Replication: Replication can enhance data consistency by ensuring that the same data exists on multiple nodes. However, maintaining consistency across replicas requires careful synchronization mechanisms.    - Write Operations:    Fragmentation: Fragmentation may require coordination among nodes for write operations that affect data distributed across different fragments. This coordination can introduce overhead and affect performance.  Replication: Write operations can be performed on any replica, potentially improving write performance by distributing the load. However, maintaining consistency among replicas requires synchronization mechanisms.    - Read Operations:    Fragmentation: Fragmentation can impact read performance if a query requires data from multiple fragments, as the DBMS needs to gather data from different nodes.  Replication: Replication can enhance read performance by allowing queries to be served from multiple replicas, reducing data access latency.    - Data Storage:    Fragmentation: Fragmented data may be stored on different nodes based on data distribution policies. Nodes may hold different portions of the schema.  Replication: Replicated data is stored on multiple nodes, with each node having a complete copy of the data or a subset of it.    - Data Access Patterns:    Fragmentation: Fragmentation aims to optimize data access patterns for specific use cases, focusing on distributing data efficiently.  Replication: Replication focuses on improving data availability and accessibility, ensuring that data can be accessed from multiple nodes.  Both fragmentation and replication serve distinct purposes in a distributed database environment, and the choice between these strategies depends on factors such as data access patterns, performance goals, consistency requirements, and fault tolerance needs.", "marks": "1", "difficulty": "3"}, {"id": "theory>Data Processing>2024>1>a", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "State four benefits of Internet in Education", "images": [], "marking_scheme": "- Vast Information Repository  - Enhanced Research Capabilities  - Global Connectivity  - Interactive Learning  - Customized learning experience  - Access to online education", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2024>1>b>i", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Explain the following types of maintenance in computing:  Corrective", "images": [], "marking_scheme": "Corrective maintenance is a type of maintenance that fixes problems that have already occurred.    - Involves fixing or repairing errors, faults, or failures after they occur.  - Reactive in nature, meaning it responds to problems that have already happened.  - Examples: Troubleshooting, debugging, patching, replacing failed components.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2024>1>b>ii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Explain the following types of maintenance in computing:  Adaptive:", "images": [], "marking_scheme": "Adaptive maintenance is a type of maintenance that prepares for future changes and needs.    - Involves modifying or upgrading systems, software, or hardware to adapt to changing requirements or environments.  - Proactive in nature, meaning it anticipates and prepares for future needs or changes.  - Examples: Upgrading hardware or software, migrating to new platforms, refactoring code.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2024>1>b>iii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "iii", "group": "", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Explain the following types of maintenance in computing:  Preventive", "images": [], "marking_scheme": "Preventive maintenance prevents problems from happening in the first place.    - Involves taking proactive measures to prevent errors, faults, or failures from occurring in the first place.  - Focuses on avoiding problems rather than fixing them after they happen.  - Examples: Regular backups, disk cleanups, virus scans, software updates, failover configurations.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2024>2>a>i", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Define the term,  file organization", "images": [], "marking_scheme": "File organization in data processing refers to the methods used to store and manage data files in a way that makes them easily accessible and efficient to use.", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2024>2>a>ii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Group the following file organization attributes under the appropriate headings as shown in Table 1  I. It does not support the use of Tapes  II. Records are inserted one after the other  III. It does not generate random keys to identify location  IV. It generates random keys to identify location    Table 1  S/No  Sequential File Organization  Indexed File Organization1.  2.  3.", "images": [], "marking_scheme": "S/No  Sequential File Organization  Indexed File Organization1. Records are inserted one after the otherIt generates random keys to identify location2. It does not generate random keys to identify location3. It does not support the use of Tapes", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2024>2>b>i", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "State two safety rules observed in a computer laboratory", "images": [], "marking_scheme": "- No food or drinks: Consuming food or drinks in a computer lab can lead to spills, damaging equipment.     - Proper electrical handling: Avoid touching electrical cords and outlets with wet hands. Use surge protectors to protect equipment from power surges.     - Proper ventilation: Ensure the computer lab is well-ventilated to prevent overheating of equipment.  - Fire safety: Know the location of fire extinguishers and emergency exits.  - Avoid physical harm: Handle computer equipment with care, avoid slamming keyboards or monitors.  - Adhere to lab rules: Follow the specific guidelines and regulations of the computer lab.  - Report issues: Immediately report any equipment malfunctions or safety hazards to the lab instructor.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2024>2>b>ii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "List three Internet browsers", "images": [], "marking_scheme": "- Google Chrome  - Mozilla Firefox  - Microsoft Edge  - Safari  - Opera  - Brave  - Vivaldi  - Samsung Internet  - UC Browser  - Yandex Browser", "marks": "3", "difficulty": "2"}, {"id": "theory>Data Processing>2024>3>a", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Explain the use of Custom Slide Show in Microsoft Power Point application", "images": [], "marking_scheme": "In Microsoft PowerPoint, a Custom Slide Show is a feature that allows you to create a tailored presentation by selecting and organizing specific slides from an existing slide deck. This enables you to present different versions of your slide show to different audiences without having to create multiple separate presentations.", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2024>3>b", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "State two functions of Rehearse Timings in Microsoft Power Point", "images": [], "marking_scheme": "- Recording Slide timings  - Setting Slide duration", "marks": "4", "difficulty": "3"}, {"id": "theory>Data Processing>2024>3>c", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "List four types of illustrations that can be added to presentation from the insert tab of Microsoft Power Point", "images": [], "marking_scheme": "- Pictures  - Shapes  - SmartArt (flowcharts, lists etc.)  - Icons  - Charts  - 3D Models", "marks": "4", "difficulty": "3"}, {"id": "theory>Data Processing>2024>4>a>i", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The Local Area Network (LAN) in a certain school is connected to the Internet. The school also has a Management Information System (MIS) which is used to enrol staff and students in the school. The system requires that users be authenticated before access is granted. Students are also allowed to use computers in the network during their leisure time  State two problems associated with uncontrolled access to the internet by students", "images": [], "marking_scheme": "- Exposure to Inappropriate content  - Cybercrime  - Cybersecurity Risks  - Distraction and Reduced Academic Performance  - Bandwidth Overload  - Cyberbullying and Online Harassment  - Addiction", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2024>4>a>ii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The Local Area Network (LAN) in a certain school is connected to the Internet. The school also has a Management Information System (MIS) which is used to enrol staff and students in the school. The system requires that users be authenticated before access is granted. Students are also allowed to use computers in the network during their leisure time  How can the problems stated in 4a(i) be prevented?", "images": [], "marking_scheme": "Implementing Effective Internet Usage Policies  - Clear guidelines: Develop comprehensive internet usage policies outlining acceptable and unacceptable online behaviors.  - Consequences: Establish clear consequences for policy violations.  Education: Educate students and staff about online safety, digital citizenship, and responsible internet use.    Network Security Measures  - Firewall implementation: Use firewalls to protect the network from external threats.     - Content filtering: Implement content filtering software to block inappropriate websites.     - Intrusion detection systems: Utilize systems to monitor network traffic for suspicious activities.  - Regular updates: Keep operating systems and software up-to-date with the latest security patches.    User Management and Authentication  - Strong password policies: Enforce strong password requirements for all users.     - Access controls: Implement role-based access controls to limit user privileges.  - Regular password changes: Require frequent password changes.  - User monitoring: Monitor user activity to detect anomalies.    Education and Awareness  - Digital literacy programs: Provide students and staff with digital literacy training.  - Cybersecurity awareness campaigns: Conduct regular campaigns to raise awareness about online threats.  - Critical thinking skills: Teach students how to evaluate online information critically.    Network Infrastructure  - Bandwidth management: Implement bandwidth management techniques to ensure fair resource allocation.  - Quality of Service (QoS): Prioritize critical network traffic to maintain performance.     - Network segmentation: Isolate sensitive systems and data from the general network.    By combining these strategies, schools can significantly reduce the risks associated with uncontrolled internet access while maximizing the benefits of technology in education", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2024>4>b", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Give one reason for users authentication before access to the system is granted", "images": [], "marking_scheme": "- Security: Prevents unauthorized access to sensitive data and system resources, protecting against data breaches and cyberattacks.  - Accountability: Tracks user actions, enabling identification of individuals responsible for system changes or errors.  - Access Control: Ensures that only authorized users can access specific parts of the system or perform certain functions.  - Data Integrity: Protects data from unauthorized modification or deletion.  - Legal Compliance: Many industries have regulations requiring user authentication to protect sensitive information.  - Resource Management: Helps manage system resources by controlling user access and usage.  - Fraud Prevention: Reduces the risk of fraudulent activities by verifying user identity.  - Auditability: Enables tracking of system usage and identifying potential security incidents.  - Non-repudiation: Prevents users from denying their actions within the system.  Licensing Enforcement: Controls software usage by requiring user authentication.", "marks": "1", "difficulty": "2"}, {"id": "theory>Data Processing>2024>4>c", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "To use the MIS, a staff is expected to login using a registered username and password. Table 2 shows login activities and the login steps to the MIS. Specify the correct order of steps in the login process in column Y using the letters A - E attached to the login activities in column X    Table 2  X: Login Activity  Y: Login StepA. System authenticates username and password B. Click on Login C. Enter Password D. Access granted/denied E. Enter username", "images": [], "marking_scheme": "X: Login Activity  Y: Login StepA. System authenticates username and password E. Enter username B. Click on Login C. Enter Password C. Enter Password B. Click on LoginD. Access granted/denied A. System authenticates username and passwordE. Enter username D. Access granted/denied", "marks": "5", "difficulty": "3"}, {"id": "theory>Data Processing>2024>5>a", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Highlight the steps to perform the following actions in Ms Access:  Creating a new table", "images": [], "marking_scheme": "Creating a New Table:    1. Open Microsoft Access and create a new database or open an existing one.  2. On the Create tab, in the Tables group, click Table Design.  3. In the Field Name column, enter the names for the fields you want to include in your table.  4. In the Data Type column, select the appropriate data type for each field (e.g., Text, Number, Date/Time, Currency, AutoNumber, Yes/No, Memo, OLE Object, Hyperlink, Lookup Wizard).  5. Optionally, set other field properties as needed (e.g., Field Size, Format, Caption, Default Value, Required, Indexed).  6. Save the table by clicking the Save button or pressing Ctrl+S.", "marks": "5", "difficulty": "3"}, {"id": "theory>Data Processing>2024>5>b", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Highlight the steps to perform the following actions in Ms Access:  Generating a query", "images": [], "marking_scheme": "Generating a Query:    1. Open your Access database.  2. Go to the Create tab.  3. In the Queries group, click Query Wizard.  4. Select the type of query you want to create (e.g., Simple Query Wizard) and click OK.  5. Select the table(s) you want to include in the query and click Next.  6. Choose the fields you want to display in the query results and click Next.  7. Specify sorting or grouping options (if needed) and click Next.  8. Give your query a name and choose whether to open the query or modify it in Design view. Click Finish.", "marks": "7", "difficulty": "3"}, {"id": "theory>Data Processing>2024>5>c", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Highlight the steps to perform the following actions in Ms Access:  Creating a split form:", "images": [], "marking_scheme": "Creating a Split Form:    1. Open your Access database.  2. Navigate to the Create tab.  3. In the Forms group, click More Forms.  4. Select Split Form.  5. Choose the table or query you want to base the form on.  6. Customize the form design as needed (optional).", "marks": "4", "difficulty": "3"}, {"id": "theory>Data Processing>2024>5>d", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "d", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Highlight the steps to perform the following actions in Ms Access:  Printing a report", "images": [], "marking_scheme": "Printing a Report:    1. Open the report you want to print.  2. Click on the \"Print\" button in the top-right corner of the screen or press Ctrl+P.  3. Select the print options as needed (e.g., number of copies, page range).  4. Click \"OK\" to print the report.  5. Alternatively, you can also export the report to a PDF or other file format by clicking \"Export\" and selecting the desired format.", "marks": "4", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>a", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A document is created in MS Word but the user realizes that part of the document are cut off when the document is print previewed in portrait orientation. Hightlight the steps to change the orientation to landscape and print the document on A4 paper.", "images": [], "marking_scheme": "Step 1: Change the Orientation    1. Open the document in MS Word.  2. Click on the \"Page Layout\" tab in the ribbon.  3. Click on the \"Orientation\" button in the \"Page Setup\" group.  4. Select \"Landscape\" from the drop-down menu.  5. If necessary, adjust the margins to ensure the content fits on the page.  6. Click on the \"Margins\" button in the \"Page Setup\" group.  7. Select a pre-defined margin setting or enter custom values.    Step 2: Set the Paper Size    1. Click on the \"Size\" button in the \"Page Setup\" group.  2. Select \"A4\" from the paper size options.    Step 3: Print the Document    1. Click on the \"Print\" button in the top-right corner of the screen or press Ctrl+P.  2. Select the printer and any additional print options as needed.  3. Click \"Print\" to print the document in landscape orientation on A4 paper.", "marks": "9", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>b>i", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "FINAL", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "A teacher working on students' result broadsheet in Microsoft Excel needed to keep the headings in \"view\" while scrolling through the results. The teacher also needed to compare each students' record with a version of the file earlier submitted to the Head of Department (HOD) to effect all suggestions.  Name the concept of keeping the headings visible while scrolling through a worksheet in Microsoft Excel", "images": [], "marking_scheme": "The concept is known as 'Freeze Panes'", "marks": "1", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>b>ii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "A teacher working on students' result broadsheet in Microsoft Excel needed to keep the headings in \"view\" while scrolling through the results. The teacher also needed to compare each students' record with a version of the file earlier submitted to the Head of Department (HOD) to effect all suggestions.    Outline the steps to keep the heading fixed while scrolling the bars in Microsoft Excel worksheet", "images": [], "marking_scheme": "To freeze panes in Excel:    1. Select the cell directly below the row you want to freeze (usually the row containing the headings).  2. Go to the \"View\" tab in the ribbon.  3. Click on \"Freeze Panes\" in the \"Window\" group.  4. Select \"Freeze Top Row\" or \"Freeze First Column\" depending on your needs.    Now, when you scroll down the worksheet, the rows above the selected row (including the headings) will remain fixed at the top of the screen.    Note: To unfreeze panes, follow the same steps and select Unfreeze Panes.", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>b>iii", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "A teacher working on students' result broadsheet in Microsoft Excel needed to keep the headings in \"view\" while scrolling through the results. The teacher also needed to compare each students' record with a version of the file earlier submitted to the Head of Department (HOD) to effect all suggestions.    Identify two actions to display each students' record at the same time on both versions of the result file.", "images": [], "marking_scheme": "1. Split the Window  2. View Side by Side  3. Split the Window", "marks": "2", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>b>iv", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "iv", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "A teacher working on students' result broadsheet in Microsoft Excel needed to keep the headings in \"view\" while scrolling through the results. The teacher also needed to compare each students' record with a version of the file earlier submitted to the Head of Department (HOD) to effect all suggestions.    Highlight the steps to achieve the named actions above.", "images": [], "marking_scheme": "1. Split the Window:    - Open both versions of the Excel file.  - Go to the \"View\" tab in the Ribbon.  - Click on \"Arrange All\" in the \"Window\" group.  - Choose an arrangement option, such as \"Vertical\" or \"Horizontal,\" to display both files side by side or one above the other. This allows the teacher to view and compare the records in both versions simultaneously.    2. View Side by Side:    - After opening both versions of the Excel file, go to the \"View\" tab.  - Click on \"View Side by Side.\" This feature automatically arranges the windows of both files next to each other, making it easier to compare records.  - Optionally, use the \"Synchronous Scrolling\" feature to scroll through both files at the same time, ensuring the same rows are visible in each file.    3. Split the Window:    - If the teacher prefers to work within the same workbook, they can use the \"Split\" feature to divide the worksheet into two scrollable panes.  - Go to the \"View\" tab and click on \"Split.\" This allows the teacher to view different sections of the same worksheet, such as the current and earlier records, at the same time.", "marks": "3", "difficulty": "3"}, {"id": "theory>Data Processing>2024>6>c", "subject": "Data Processing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "List two gadgets needed to display the content of a computer to an audience in an auditorium", "images": [], "marking_scheme": "- Projector  - Large Screen or Display  - HDMI or VGA cables  - Laptop or Computer", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>1>a>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Explain the following terms:    data processing;", "images": [], "marking_scheme": "Data Processing is the process of collecting, organizing, analyzing, and transforming raw data into meaningful and useful information", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>1>a>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Explain the following terms:  data collation.", "images": [], "marking_scheme": "Data Collation is the process of gathering and combining data from different sources into a single, organized format for analysis or reporting.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>1>b", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Describe Data Processing Cycle.", "images": [], "marking_scheme": "The Data Processing Cycle is a sequence of steps or phases that raw data goes through to be converted into meaningful, usable information. It's a fundamental concept in information technology and data management, outlining the systematic approach to handling data.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>1>c", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "State four benefits of the computer as a tool for processing data.", "images": [], "marking_scheme": "1. Speed – Computers can process large volumes of data in seconds, much faster than humans.    2. Accuracy – With correct input, computers provide highly accurate results with minimal errors.    3. Storage – They can store vast amounts of data in a compact form, making it easy to retrieve and update.    4. Automation – Computers can automate repetitive tasks like calculations, data entry, and report generation.    5. Efficiency – They improve productivity by handling multiple tasks quickly and effectively.    6. Security – Data stored on computers can be protected using passwords, encryption, and backups.    7. Easy Retrieval – Processed or stored data can be quickly searched and retrieved for use.    8. Consistency – Results remain consistent when the same operations are performed multiple times.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>2>a>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "FINAL", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:    A;", "images": ["Data Processing/imgs/2025/WRN2YP.jpg"], "marking_scheme": "Monitor: This is the screen used to display the visual output of the computer.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>2>a>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "FINAL", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  B;", "images": ["Data Processing/imgs/2025/WRN2YP.jpg"], "marking_scheme": "Printer: A device used to produce hard copies of documents or images from the computer.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>2>a>iii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "iii", "group": "FINAL", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  C;", "images": ["Data Processing/imgs/2025/WRN2YP.jpg"], "marking_scheme": "Mouse: A pointing device used to control the cursor and interact with graphical elements on the screen.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>2>a>iv", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "iv", "group": "FINAL", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  D;", "images": ["Data Processing/imgs/2025/WRN2YP.jpg"], "marking_scheme": "Keyboard: An input device used to type data, commands, and control functions into the computer.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>2>b", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "For each device in the setup, tick (✓) the box to show if it is an input device or an output device.    DeviceInput DeviceOutput DeviceABCD", "images": [], "marking_scheme": "DeviceInput DeviceOutput DeviceA✓B✓C✓D✓", "marks": "4", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>2>c", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Name two devices that can be used for both input and output operations.", "images": [], "marking_scheme": "1. Touchscreen  Input: Detects finger touches/stylus input (e.g., tapping, swiping).  Output: Displays visual feedback (e.g., apps, videos).  Examples: Smartphones, ATMs, interactive kiosks.    2. Network Interface Card (NIC)  Input: Receives data from a network (e.g., downloads).  Output: Sends data to a network (e.g., uploads).  Example: Ethernet/Wi-Fi cards in laptops.    3. Hard Disk Drive (HDD)/Solid State Drive (SSD)  Input: Writes (saves) data to the disk.  Output: Reads (retrieves) data from the disk.  Example: Loading a game (output) and saving progress (input).    4. USB Drive (Flash Drive)  Input: Stores data transferred from a computer.  Output: Provides data to the computer when accessed.    5. Modem  Input: Receives signals from the internet (download).  Output: Sends signals to the internet (upload).    6. Headset with Microphone  Input: Captures audio via the microphone.  Output: Plays sound through the speakers.    7. CD/DVD-RW Drive  Input: Burns (writes) data to discs.  Output: Reads data from discs.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>3>a>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "With the aid of well-labelled diagram, explain the following modes of information transmission:    simplex;", "images": ["Data Processing/imgs/2025/M9WBLX.png"], "marking_scheme": "Simplex mode is a type of communication where data flows in only one direction. One device is the sender, and the other is the receiver. The receiver cannot send data back to the sender.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>3>a>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "With the aid of well-labelled diagram, explain the following modes of information transmission:  half duplex;", "images": ["Data Processing/imgs/2025/ND9DEY.png"], "marking_scheme": "Half duplex communication allows data to flow in both directions, but only one direction at a time. The sender and receiver can both transmit and receive data, but not simultaneously.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>3>a>iii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "iii", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "With the aid of well-labelled diagram, explain the following modes of information transmission:  full duplex.", "images": ["Data Processing/imgs/2025/BW9RXK.png"], "marking_scheme": "Full-duplex mode is a two-way, simultaneous communication channel. This means that data can flow in both directions between the sender and the receiver at the same time. It's like a two-lane highway where traffic can move in both directions concurrently without interfering with each other.    This mode allows for efficient and continuous exchange of information, as both parties can transmit and receive data independently and without waiting for the other side to finish.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION A>3>b>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "State one example of:    simplex;  mode of information transmission.", "images": [], "marking_scheme": "1. Television broadcast – Information flows from the TV station to your TV only.    2. Radio broadcast – Sound is transmitted from the radio station to the receiver.    3. Keyboard to computer – The keyboard only sends signals to the computer.    4. Mouse to computer – Movement and clicks are only sent from the mouse to the system.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>3>b>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "State one example of:  half duplex;  mode of information transmission.", "images": [], "marking_scheme": "1. Walkie-talkies – Only one person can speak at a time while the other listens.    2. Citizen Band (CB) radios – Communication happens in both directions, but not simultaneously.    3. Two-way intercom systems – You must press a button to talk, then release it to listen.    4. Older computer networks using Ethernet hubs – Data could be sent and received, but not at the same time.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>3>b>iii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "iii", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "State one example of:  full duplex,  mode of information transmission.", "images": [], "marking_scheme": "1. Mobile phone calls – Both parties can speak and hear each other at the same time.    2. Video conferencing apps (e.g., Zoom, Teams) – Audio and video are sent and received simultaneously.    3. Modern computer networks using switches – Devices can send and receive data at the same time.    4. Telephone landlines – Allow simultaneous two-way communication.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>3>c", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Name one component of a data communication system.", "images": [], "marking_scheme": "1. Sender – The device or person that initiates the message.    2. Receiver – The device or person that receives the message.    3. Transmission medium – The physical path (e.g., cables, air) through which data travels.    4. Message – The actual data or information being transmitted.    5. Protocol – The set of rules that govern data communication.    6. Modem – Converts digital signals to analog and vice versa for transmission over telephone lines.    7. Encoder/Decoder – Converts data into suitable form for transmission and back to original form at reception.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>4>a", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Differentiate between hackers and spammers.", "images": [], "marking_scheme": "Hackers are individuals who gain unauthorized access to computer systems to steal data, disrupt operations, or exploit security weaknesses. Spammers, on the other hand, send unsolicited messages—usually emails—to advertise, spread malware, or scam users. While hackers operate stealthily, spammers are more visible due to the high volume of unwanted messages they send.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>4>b", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "State one importance of add-in in MS Excel.", "images": [], "marking_scheme": "1. Data analysis and visualization enhancement – Add-ins like Power Pivot and Power Map help analyze large data sets and visualize them in 3D maps.    2. Automation of repetitive tasks – Add-ins can include macros and tools that automate common workflows, saving time.    3. Integration with external databases and applications – Some add-ins allow Excel to connect with SQL databases or APIs for real-time data.    4. Advanced statistical and mathematical functions – Tools like the Analysis ToolPak add-in offer regression, histograms, and other advanced features.    5. Custom user-defined functions – Add-ins let users create and use their own Excel functions not included by default.    6. Improved productivity – Productivity add-ins add shortcuts, templates, and formatting tools to make work faster.    7. Enhanced charting and graphing – Some add-ins allow users to create advanced or specialized charts that Excel doesn't natively support.    8. Financial modeling and forecasting – Add-ins can support scenarios, goal seek, and what-if analysis for budgeting and investment modeling.    9. Real-time data feeds – Market and financial data add-ins provide constantly updating information inside worksheets.    10. Customization of Excel interface – Add-ins can add new tabs, buttons, or menus tailored to specific business tasks or user preferences.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>4>c>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Explain the following terms in computing:    cookies;", "images": [], "marking_scheme": "Cookies in computing are small text files stored on a user's computer by a website. They are used to remember information about the user, such as login status, preferences, or items in a shopping cart. When the user revisits the website, the stored cookie data helps provide a more personalized and efficient browsing experience. Cookies can be session-based (temporary) or persistent (saved for future visits).", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>4>c>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Explain the following terms in computing:  plugin;", "images": [], "marking_scheme": "Plugin in computing is a software component that adds specific features or functionalities to an existing computer program or application. It \"plugs in\" to the main software to extend its capabilities without altering the core program. For example, web browsers use plugins to play videos, display PDFs, or block ads. Plugins allow users to customize and enhance their software experience.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION A>4>c>iii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "iii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Explain the following terms in computing:  web crawlers.", "images": [], "marking_scheme": "Web crawlers are automated programs or bots used by search engines to systematically browse the internet and index web pages. They \"crawl\" from one webpage to another by following links, gathering data about the content, structure, and keywords of websites. This information helps search engines organize and rank pages so users can find relevant results quickly.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION B>5>a", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "FINAL", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Figure 2 is an interface of an application software.  Use it to answer questions 5(a) to 5(c).     Identify the type of application whose interface is shown in Figure 2.", "images": ["Data Processing/imgs/2025/9G6RFM.jpg"], "marking_scheme": "The type of application shown in Figure 2 is Microsoft PowerPoint, which is a presentation software used to create slideshows for presentations.", "marks": "1", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION B>5>b>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Outline the steps to:    insert a new slide to the interface;", "images": [], "marking_scheme": "Method 1: Using the Ribbon  1. Open your PowerPoint presentation.  2. Navigate to the slide before where you want the new slide.  3. Go to the Home tab in the ribbon.  4. Click New Slide (or the dropdown arrow to choose a layout).    Method 2: Right-Click (Context Menu)  1. Right-click on a slide thumbnail in the left-side panel.  2. Select New Slide from the menu.    Method 3: Keyboard Shortcut  Windows: Press Ctrl + M.  Mac: Press Cmd + M.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION B>5>b>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Outline the steps to:  delete a slide from the interface.", "images": [], "marking_scheme": "1. Open your PowerPoint presentation.    2. In the left pane (slide thumbnail view), click to select the slide you want to delete.    3. Right-click on the selected slide.    4. Choose Delete Slide from the context menu.    Alternatively, after selecting the slide, you can simply press the Delete key on your keyboard to remove it.", "marks": "2", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION B>5>c", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "State two examples of the application in Figure 2.", "images": [], "marking_scheme": "1. Microsoft PowerPoint: The most widely used presentation software globally, part of the Microsoft Office suite.    2. Google Slides: A free, web-based presentation program offered as part of Google Workspace, known for its strong collaboration features.    3. Apple Keynote: Apple's presentation software, known for its elegant designs, intuitive interface, and smooth animations, primarily for macOS and iOS users.    4. Prezi: A unique presentation tool that uses a non-linear, zoomable canvas instead of traditional slides, allowing for dynamic and engaging presentations.    5. LibreOffice Impress: A free and open-source presentation program that is part of the LibreOffice suite, offering functionality similar to PowerPoint.", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION B>5>d>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Give two:    uses of the application in Figure 2;", "images": [], "marking_scheme": "1. Creating slide presentations for meetings and lectures    2. Designing training materials and tutorials    3. Making business proposals and project reports    4. Preparing visual aids for speeches and seminars    5. Developing marketing and sales presentations", "marks": "2", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION B>5>d>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Give two:  differences between transitions and animations in the application shown in Figure 2.", "images": [], "marking_scheme": "1. Purpose:  - Transitions control how one slide moves or changes to the next slide during a presentation.  - Animations control the movement or appearance of individual elements (like text, images, or shapes) within a single slide.    2. Scope:  - Transitions apply to the entire slide as it moves to the next.  - Animations apply only to specific objects or content on a slide.    3. Timing:  - Transitions occur between slides.  - Animations happen during the display of a single slide.    4. Types of Effects:  - Transitions include effects like fade, wipe, push, or dissolve between slides.  - Animations include effects like fade in/out, fly in, bounce, or zoom applied to text or objects.    5. User Control:  - Transitions usually trigger when you move to the next slide (manually or automatically).  - Animations can be triggered by clicks, with delays, or in sequence while the slide is displayed.", "marks": "6", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION B>5>e>i", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Highlight the steps to:    run slideshow in the application shown in Figure 2;", "images": [], "marking_scheme": "1. Click the \"Slide Show\" tab on the Ribbon at the top of the window.    2. Select \"From Beginning\" to start the slideshow from the first slide, or \"From Current Slide\" to start from the slide you are currently viewing.    3. Alternatively, press the F5 key on the keyboard to start the slideshow from the beginning.    4. You can also press Shift + F5 to start the slideshow from the current slide.    These actions will launch the presentation in full-screen slideshow mode.", "marks": "3", "difficulty": "1"}, {"id": "theory>Data Processing>2025>SECTION B>5>e>ii", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Highlight the steps to:  print a handout of 6 slides on a page of the application shown in Figure 2.", "images": [], "marking_scheme": "1. Click on the File tab (top-left corner).    2. Select Print from the menu.    3. In the Print settings, click the dropdown under Print Layout or Full Page Slides.    4. Choose Handouts (6 slides per page) from the layout options.    5. Adjust any other print settings as needed (like printer selection, number of copies).    6. Click Print to start printing the handouts.    This will print 6 slides arranged neatly on each page.", "marks": "4", "difficulty": "2"}, {"id": "theory>Data Processing>2025>SECTION B>6>a", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "You are provided with a list of existing contacts in a database. Describe in detail, the step-by-step approach to:    create;  a mail merge using a template in MS Word.", "images": [], "marking_scheme": "(i) Prepare the contact list in Excel with clear column headers (e.g., First Name, Last Name, Email).    (ii) Open Microsoft Word.    (iii) Open the mail merge template document you want to use. If none exists, create a new blank document and format it as needed.    (iv) Click the Mailings tab on the Ribbon.    (v) Click Start Mail Merge and select the document type (e.g., Letters, Labels, Envelopes).    (vi) Click Select Recipients and choose Use an Existing List.    (vii) Browse to locate and select your existing contacts database (e.g., an Excel file).    (viii) If prompted, select the worksheet or table that contains your contact list and confirm the data range.    (ix) Place the cursor in the document where personalized data should appear.    (x) Click Insert Merge Field and select the fields (e.g., First_Name, Last_Name, Address) to insert them in the appropriate places.    (xi) Repeat as needed for all fields you want to personalize.    (xii) Format the document, adjusting fonts, spacing, and layout around the merge fields to ensure a professional look.    (xiii) Save the main mail merge document to preserve the setup for later use.", "marks": "17", "difficulty": "3"}, {"id": "theory>Data Processing>2025>SECTION B>6>b", "subject": "Data Processing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "You are provided with a list of existing contacts in a database. Describe in detail, the step-by-step approach to:  preview and complete,  a mail merge using a template in MS Word.", "images": [], "marking_scheme": "(i) With the mail merge document open, go to the Mailings tab.    (ii) Click Preview Results to see how the merged data populates the fields.    (iii) Use the left and right arrow buttons next to Preview Results to scroll through individual records for verification.    (iv) If you find any errors, make corrections to the main document or update the recipient list as needed.    (v) Once satisfied, click Finish & Merge.    (vi) Choose one of the following options:  - Edit Individual Documents to generate a new document containing all merged letters for final review or printing;  - Print Documents to send the merged documents directly to a printer;  - Send E-mail Messages if merging emails.    (vii) If you select Edit Individual Documents, specify whether to merge all records or a range, then click OK.    (viii) Save the merged document if you edited or created individual files.    (ix) Close the mail merge main document when finished.    (x) It is recommended to back up the original contact list and any merged documents to prevent data loss.", "marks": "3", "difficulty": "3"}];